@layer mergora.components {
  .mrg-visually-hidden {
    position: absolute;
    inline-size: 1px;
    block-size: 1px;
    margin: -1px;
    overflow: hidden;
    clip-path: inset(50%);
    white-space: nowrap;
    border: 0;
    padding: 0;
  }

  .mrg-visually-hidden[data-reveal-on-focus="true"]:focus-visible {
    position: fixed;
    z-index: var(--mrg-semantic-layer-tooltip);
    inset-block-start: var(--mrg-semantic-space-stack-sm);
    inset-inline-start: var(--mrg-semantic-space-inline-sm);
    inline-size: auto;
    block-size: auto;
    margin: 0;
    overflow: visible;
    clip-path: none;
    white-space: normal;
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
    border-radius: var(--mrg-semantic-radius-control);
    padding: var(--mrg-semantic-space-stack-sm) var(--mrg-semantic-space-inline-md);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    box-shadow: 0 0 0 var(--mrg-component-focus-indicator-width)
      var(--mrg-component-focus-indicator-contrast-background);
    outline: var(--mrg-component-focus-indicator-width) solid
      var(--mrg-component-focus-indicator-color);
    outline-offset: var(--mrg-component-focus-indicator-offset);
  }

  @media (forced-colors: active) {
    .mrg-visually-hidden[data-reveal-on-focus="true"]:focus-visible {
      color: CanvasText;
      background: Canvas;
      border-color: CanvasText;
      box-shadow: none;
      outline-color: Highlight;
      forced-color-adjust: auto;
    }
  }
}

import {
  forwardRef,
  type AnchorHTMLAttributes,
  type HTMLAttributes,
  type ReactElement,
  type Ref,
} from "react";

import "./visually-hidden.css";

interface VisuallyHiddenOwnProps {
  /** Reveals the hidden content when it receives keyboard focus, for skip links and similar controls. */
  readonly revealOnFocus?: boolean;
}

/** Valid native props follow the selected element. The default element is span. */
export type VisuallyHiddenProps = VisuallyHiddenOwnProps &
  (
    | ({
        /** Selects the native span, div, or anchor contract; span is the default. */
        readonly as?: "span";
      } & HTMLAttributes<HTMLSpanElement>)
    | ({
        /** Selects the native span, div, or anchor contract; span is the default. */
        readonly as: "div";
      } & HTMLAttributes<HTMLDivElement>)
    | ({
        /** Selects the native span, div, or anchor contract; span is the default. */
        readonly as: "a";
      } & AnchorHTMLAttributes<HTMLAnchorElement>)
  );

function joinClassNames(className: string | undefined): string {
  return className === undefined || className.trim().length === 0
    ? "mrg-visually-hidden"
    : `mrg-visually-hidden ${className}`;
}

export const VisuallyHidden = forwardRef<HTMLElement, VisuallyHiddenProps>(function VisuallyHidden(
  { as = "span", className, revealOnFocus = false, ...nativeProps },
  ref,
): ReactElement {
  const sharedProps = {
    className: joinClassNames(className),
    "data-reveal-on-focus": revealOnFocus ? "true" : undefined,
    "data-slot": "visually-hidden",
  };
  if (as === "a") {
    return (
      <a
        {...(nativeProps as AnchorHTMLAttributes<HTMLAnchorElement>)}
        {...sharedProps}
        ref={ref as Ref<HTMLAnchorElement>}
      />
    );
  }
  if (as === "div") {
    return (
      <div
        {...(nativeProps as HTMLAttributes<HTMLDivElement>)}
        {...sharedProps}
        ref={ref as Ref<HTMLDivElement>}
      />
    );
  }
  return (
    <span
      {...(nativeProps as HTMLAttributes<HTMLSpanElement>)}
      {...sharedProps}
      ref={ref as Ref<HTMLSpanElement>}
    />
  );
});

VisuallyHidden.displayName = "VisuallyHidden";
